INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '998c9b1d-63bc-4eec-a5ba-caadaeb74719',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost DMatrix Device Management — CPU/GPU Placement in XGBoost 2.0+$escape$,
  $escape$XGBoost doesn't expose raw tensor ops, but `DMatrix` is its foundational data structure — the boundary where device placement decisions happen. In XGBoost 2.0+, the `gpu_hist` tree method was deprecated; GPU acceleration is now controlled entirely via the `device` parameter on both `DMatrix` and training params. Pass `device='cuda'` (or `device='cuda:0'` for a specific GPU) when constructing `DMatrix` to stage data on-device and avoid PCIe round-trips during training.

For large datasets, prefer `QuantileDMatrix` over `DMatrix` on GPU — it computes quantile sketches during construction, consuming significantly less GPU memory by avoiding the full dense matrix copy. XGBoost also accepts `cupy` arrays directly; if your preprocessing pipeline already lives on GPU (e.g., RAPIDS cuDF), pass the cuDF DataFrame straight to `QuantileDMatrix` and data never touches the host. Mismatched devices between your `DMatrix` and `params['device']` will trigger an implicit copy — always align them explicitly to avoid silent performance degradation.$escape$,
  $escape$import xgboost as xgb
import cupy as cp

# Data already on GPU via cupy — no host round-trip
X_gpu = cp.array(X_train)
y_gpu = cp.array(y_train)

# QuantileDMatrix: GPU-resident, memory-efficient sketch
dtrain = xgb.QuantileDMatrix(X_gpu, label=y_gpu)

params = {
    "tree_method": "hist",
    "device": "cuda",          # XGBoost 2.0+ — replaces gpu_hist
    "objective": "binary:logistic",
    "eval_metric": "logloss",
}

model = xgb.train(params, dtrain, num_boost_round=200)$escape$,
