INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '26933e04-4266-41b1-ad1f-5a6e3b8defcf',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost Training Loop — Gradients, Hessians, and the Boosting Step Explained$escape$,
  $escape$XGBoost's training loop has no forward pass or backprop in the neural-network sense. Each boosting round is a second-order Taylor approximation of your loss. Given current predictions, XGBoost computes first-order gradients (`g`) and second-order hessians (`h`) for every sample. A new tree is then fit to minimize the weighted sum of these statistics — leaf weights are solved analytically as `-G / (H + lambda)` where G and H are summed gradient/hessian per leaf. This is the 'optimizer step': no SGD, no Adam — just a closed-form Newton update per leaf, scaled by `eta` (learning rate/shrinkage). The `num_boost_round` parameter controls how many trees (steps) are added. You can hook directly into this loop via a custom `obj` function that returns `(grad, hess)` arrays, giving you full control over the loss surface. Built-in objectives like `reg:squarederror` or `binary:logistic` do this internally. Monitoring via `evals` dict lets you track per-round metric convergence without retraining.$escape$,
  $escape$import xgboost as xgb
import numpy as np

def focal_obj(preds, dtrain):
    labels = dtrain.get_label()
    gamma = 2.0
    p = 1.0 / (1.0 + np.exp(-preds))
    grad = (p - labels) * ((1 - p) ** gamma) * (1 - gamma * p * np.log(np.clip(p, 1e-7, 1)))
    hess = p * (1 - p) * ((1 - p) ** gamma)
    return grad, hess

dtrain = xgb.DMatrix(X_train, label=y_train)
deval  = xgb.DMatrix(X_val,   label=y_val)

params = {"eta": 0.05, "max_depth": 6, "lambda": 1.0, "tree_method": "hist"}
evals_result = {}
model = xgb.train(
    params, dtrain, num_boost_round=300,
    obj=focal_obj,
    evals=[(dtrain, "train"), (deval, "val")],
    evals_result=evals_result,
    callbacks=[xgb.callback.EarlyStopping(rounds=20)]
)$escape$,
  $escape$python$escape$,
