INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '37a551ea-9485-4544-a264-4dc2441fbbf3',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost QuantileDMatrix — Streaming Large Datasets with the Iterator Protocol$escape$,
  $escape$XGBoost doesn't have a DataLoader in the PyTorch sense, but `QuantileDMatrix` with a custom `xgb.DataIter` subclass gives you the same chunked-loading pattern — and it's the only way to train on datasets that don't fit in RAM without resorting to external-memory DMatrix files.

Subclass `xgb.DataIter`, implement `next()` and `reset()`, then pass the iterator directly to `QuantileDMatrix`. XGBoost calls `next()` repeatedly to feed chunks, computes quantile sketches incrementally (not in one shot), and discards each chunk before loading the next — keeping peak memory proportional to chunk size, not total dataset size. Crucially, `QuantileDMatrix` is required here; plain `DMatrix` does not accept iterators.

Shuffle at the chunk level inside `reset()` or before constructing each chunk in `next()` — XGBoost itself performs no data shuffling. For augmentation (e.g., SMOTE on imbalanced chunks), apply it inside `next()` before calling `input_data()`. The `cache_prefix` arg writes temp quantile cache files to disk; set it explicitly to control I/O location in containerised environments.$escape$,
  $escape$import xgboost as xgb
import numpy as np

class ChunkedIter(xgb.DataIter):
    def __init__(self, chunks):
        self._chunks = chunks
        self._it = 0
        super().__init__(cache_prefix="/tmp/xgb_cache")

    def next(self, input_data):
        if self._it == len(self._chunks):
            return 0
        X, y = self._chunks[self._it]
        input_data(data=X, label=y)
        self._it += 1
        return 1

    def reset(self):
        self._it = 0
        np.random.shuffle(self._chunks)  # chunk-level shuffle

chunks = [(np.random.randn(2000, 20), np.random.randint(0, 2, 2000)) for _ in range(8)]
Xy = xgb.QuantileDMatrix(ChunkedIter(chunks))
booster = xgb.train({"tree_method": "hist", "device": "cpu"}, Xy, num_boost_round=200)$escape$,
  $escape$python$escape$,
