INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '416c0e6a-d5f7-4c93-98af-5c4b6d72d277',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost Transfer Learning — Fine-Tuning vs Leaf-Based Feature Extraction$escape$,
  $escape$XGBoost supports transfer learning via two distinct mechanisms. The first is model continuation: pass `xgb_model` to `xgb.train()` to resume from a pretrained checkpoint, appending new trees to the existing ensemble. This is fine-tuning — the old trees are frozen structurally, and new boosting rounds adapt to your domain data. The second is feature extraction: call `model.predict(dmatrix, pred_leaf=True)` to get each sample's leaf index per tree. These indices are sparse categorical embeddings of the pretrained tree structure — feed them into a downstream linear model or a new XGBoost model trained on the target task.

The `process_type='update'` + `updater='refresh'` combo lets you re-fit leaf weights of existing trees without altering splits — the closest XGBoost analog to freezing backbone layers. Useful when your source and target distributions share feature structure but differ in label scale. For tabular domain shift, fine-tuning (model continuation) typically outperforms feature extraction unless your target dataset is tiny (<500 rows), where leaf embeddings reduce overfitting risk.$escape$,
  $escape$import xgboost as xgb
import numpy as np

# Fine-tuning: continue training from pretrained model
dtrain_target = xgb.DMatrix(X_target, label=y_target)
params = {"eta": 0.01, "max_depth": 6, "objective": "reg:squarederror"}
model_ft = xgb.train(params, dtrain_target, num_boost_round=50,
                     xgb_model="pretrained.ubj")  # appends 50 new trees

# Feature extraction: leaf indices as embeddings
pretrained = xgb.Booster()
pretrained.load_model("pretrained.ubj")
leaf_feats = pretrained.predict(dtrain_target, pred_leaf=True)  # shape: (n, n_trees)

# Train lightweight model on leaf embeddings
dleaf = xgb.DMatrix(leaf_feats, label=y_target)
model_fe = xgb.train({"max_depth": 3, "objective": "reg:squarederror"},
                     dleaf, num_boost_round=30)$escape$,
  $escape$python$escape$,
