INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0bc92064-687e-4263-9dcb-a582ec3ab42a',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost Debugging — Diagnosing NaN Loss and Gradient Explosions$escape$,
  $escape$NaN loss in XGBoost almost always traces back to three sources: extreme feature values, a learning rate that's too aggressive, or a degenerate split producing zero-sample leaf nodes. XGBoost's gradient boosting computes first-order (grad) and second-order (hess) statistics per leaf — if hess sums to zero or near-zero, the leaf weight formula `w = -G/H` explodes.

Set `min_child_weight` (minimum sum of hessians in a leaf) to a value above your noise floor — default is 1, but for imbalanced or sparse data, try 5–10. Pair this with `max_delta_step` (caps the absolute weight update per tree, default 0) — setting it to 1 clamps runaway updates without shrinking your learning rate globally.

For gradient flow visibility, enable `eval_metric=['logloss', 'error']` with an `evals` watchlist and pass `verbose_eval=10`. XGBoost will surface per-round metrics so you can pinpoint which iteration diverges. Also set `nthread=1` during debugging — parallel tree construction can obscure the exact split causing NaN propagation.$escape$,
  $escape$import xgboost as xgb
import numpy as np

X_train, y_train = np.random.randn(1000, 20), np.random.randint(0, 2, 1000)
dtrain = xgb.DMatrix(X_train, label=y_train)
dval = xgb.DMatrix(X_train[:200], label=y_train[:200])

params = {
    "objective": "binary:logistic",
    "eta": 0.1,
    "max_depth": 6,
    "min_child_weight": 5,   # prevents near-zero hessian leaves
    "max_delta_step": 1,     # clamps exploding leaf weights
    "eval_metric": ["logloss", "error"],
    "nthread": 1,            # deterministic for debugging
}

evals = [(dtrain, "train"), (dval, "val")]
bst = xgb.train(params, dtrain, num_boost_round=100,
                evals=evals, verbose_eval=10)$escape$,
  $escape$python$escape$,
