INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c21c3d6a-d16a-4ccc-9a33-d733be7b1152',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost Custom Objectives with JAX — Deriving grad and hess via jit, grad, vmap$escape$,
  $escape$XGBoost's custom `obj` parameter requires a function returning per-sample `(grad, hess)` arrays — the first and second derivatives of your loss with respect to raw predictions. Hand-deriving these for exotic losses like focal or Huber is tedious and error-prone. JAX eliminates both problems: define the loss once per sample, apply `jax.grad` twice to get gradient and hessian automatically, wrap with `vmap` to vectorize over the batch, and `jit` to XLA-compile the entire pipeline.

On first call, XLA traces the computation graph and emits optimized machine code — subsequent `obj` calls during `xgb.train` are near-zero overhead. This matters because XGBoost invokes your objective once per boosting round; with 500 rounds and 100k samples, unoptimized Python loops are a bottleneck. The `jit`+`vmap` combination also preserves numerical stability since JAX differentiates through `jax.nn.sigmoid` and `jnp.log` symbolically rather than finite-differencing. XGBoost then uses these exact gradients to fit each new tree's leaf values — precision here directly impacts model convergence.$escape$,
  $escape$import jax
import jax.numpy as jnp
import xgboost as xgb
import numpy as np

# Per-sample focal loss (raw margin input, not probability)
def focal_loss(pred, label, gamma=2.0):
    p = jax.nn.sigmoid(pred)
    return -(((1 - p) ** gamma) * jnp.log(p + 1e-7) * label)

grad_fn = jax.jit(jax.vmap(jax.grad(focal_loss)))
hess_fn = jax.jit(jax.vmap(jax.grad(jax.grad(focal_loss))))

def focal_obj(preds: np.ndarray, dtrain: xgb.DMatrix):
    p = jnp.array(preds)
    y = jnp.array(dtrain.get_label())
    return np.array(grad_fn(p, y)), np.array(hess_fn(p, y))

dtrain = xgb.DMatrix(X_train, label=y_train)
xgb.train({"tree_method": "hist", "base_score": 0.5}, dtrain, num_boost_round=300, obj=focal_obj)$escape$,
  $escape$python$escape$,
