INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ee806e97-86da-40cc-8eb4-2eaa54808b3d',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost Native vs Sklearn API — Keras-Style Abstraction Tradeoffs$escape$,
  $escape$XGBoost mirrors Keras's Sequential vs Functional API split. The sklearn wrapper (`XGBClassifier`/`XGBRegressor`) is your Sequential API — clean, opinionated, minimal boilerplate. But it hides the `Booster` object and limits low-level control. The native `xgb.train()` API is your Functional API: you build the `DMatrix` manually, pass `evals`, define custom `feval` metrics, and inject `xgb.callback.*` objects directly into training. This is where real control lives. Custom callbacks in XGBoost (`TrainingCallback` subclass with `after_iteration`) map directly to Keras's `on_epoch_end` — you get full access to the booster mid-training to prune trees, adjust `eta`, or implement early stopping logic yourself. For production pipelines, prefer `xgb.train()` with explicit `num_boost_round` and `evals_result` dict injection over sklearn's `n_estimators`. You get deterministic tree counts, live eval curves without re-fitting, and the ability to resume training from a saved `model.save_model()` checkpoint — none of which are cleanly available through the sklearn shim.$escape$,
  $escape$import xgboost as xgb
from xgboost.callback import TrainingCallback

class LRDecayCallback(TrainingCallback):
    def after_iteration(self, model, epoch, evals_log):
        if epoch % 50 == 0 and epoch > 0:
            model.set_param('eta', model.attr('eta') or 0.1)
        return False

dtrain = xgb.DMatrix(X_train, label=y_train)
dval   = xgb.DMatrix(X_val,   label=y_val)

params = {'objective': 'binary:logistic', 'eta': 0.1, 'max_depth': 6, 'eval_metric': 'logloss'}
evals_result = {}

booster = xgb.train(
    params, dtrain,
    num_boost_round=300,
    evals=[(dtrain, 'train'), (dval, 'val')],
    evals_result=evals_result,
    callbacks=[LRDecayCallback()],
    verbose_eval=False
)$escape$,
  $escape$python$escape$,
