INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2162967f-3e1c-42b7-be57-394a447d61b0',
  '00000000-0000-0000-0000-000000000001',
  $escape$XGBoost in Production — Model Export, ONNX Conversion, and Serving Without the Runtime$escape$,
  $escape$XGBoost's native `.ubj` (binary JSON) format via `booster.save_model('model.ubj')` is the fastest checkpoint, but it locks you into the XGBoost runtime in serving. For polyglot inference stacks, convert to ONNX using `onnxmltools.convert_xgboost()` — this lets you serve via ONNX Runtime, which eliminates the XGBoost dependency entirely and unlocks hardware-accelerated execution on CUDA/DirectML providers.

Key gotchas: ONNX conversion requires specifying `initial_types` with the exact feature count and dtype — a mismatch silently produces wrong predictions. Always validate outputs against the native booster post-conversion using a held-out batch. For tree-method='hist' models, set `n_estimators` conservatively before export — ONNX graphs grow linearly with tree count and inflate inference latency.

For REST serving, `xgboost.Booster.inplace_predict()` skips DMatrix construction entirely and is ~30% faster than `predict()` on raw numpy arrays. Pair with FastAPI and a lifespan context manager to load the booster once at startup, not per request. Enable `nthread` to match your container's vCPU count.$escape$,
  $escape$import xgboost as xgb
import onnxmltools
from onnxmltools.convert.common.data_types import FloatTensorType
import numpy as np

# Save native (fastest reload)
bst = xgb.Booster()
bst.load_model('model.ubj')

# Convert to ONNX — specify exact input shape
initial_type = [('float_input', FloatTensorType([None, 28]))]
onnx_model = onnxmltools.convert_xgboost(bst, initial_types=initial_type)

# Validate parity
X_val = np.random.rand(100, 28).astype(np.float32)
native_preds = bst.inplace_predict(X_val)

import onnxruntime as rt
sess = rt.InferenceSession(onnx_model.SerializeToString())
onnx_preds = sess.run(None, {'float_input': X_val})[0]

np.testing.assert_allclose(native_preds, onnx_preds, rtol=1e-4)$escape$,
  $escape$python$escape$,
